#include <stdio.h>

int main() {
    int number_people;
    scanf("%d", &number_people);

    int fingers[number_people];
    for (int i = 0; i < number_people; i++) {
        scanf("%d", &fingers[i]);
    }

    int sum_fingers = 0;
    for (int i = 0; i < number_people; i++) {
        sum_fingers += fingers[i];
    }

    int fingers_hand[] = {1, 2, 3, 4, 5};
    int counter = 0;

    for (int i = 0; i < 5; i++) {
        int all_fingers = fingers_hand[i] + sum_fingers;
        while (all_fingers > 0) {
            all_fingers -= (number_people + 1);
            if (all_fingers == 1) {
                counter++;
                break;
            }
        }
    }

    printf("%d\n", 5 - counter);
    return 0;
}
